// Error handling middleware with logging
app.use((err, req, res, next) => {
    const clientIp = req.headers['x-forwarded-for'] || req.ip;
    const username = req.headers['x-username'] || 'anonymous';

    auditLogger.error(`Unhandled error: ${err.message}`, {
        error: err.stack,
        method: req.method,
        path: req.path,
        username,
        ip: clientIp
    });

    // Write error directly to error log
    const errorEntry = `[${new Date().toISOString()}] ERROR: user=${username}, ip=${clientIp}, path=${req.path}, error=${err.message}\n${err.stack}\n`;
    fs.appendFileSync(path.join(logsDir, 'error-detail.log'), errorEntry);

    res.status(500).json({ success: false, message: 'Internal server error' });
});

// 404 handler with logging
app.use((req, res) => {
    const clientIp = req.headers['x-forwarded-for'] || req.ip;
    const username = req.headers['x-username'] || 'anonymous';

    auditLogger.warn(`404 Not Found: ${req.method} ${req.path}`, {
        username,
        ip: clientIp,
        userAgent: req.headers['user-agent']
    });

    res.status(404).json({ success: false, message: 'Route not found' });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
    auditLogger.info(`Audit logging server started on port ${PORT}`);
    console.log(`Server running on http://localhost:${PORT}`);
    console.log(`Logs directory: ${logsDir}`);
});

module.exports = app;